import sys
input = sys.stdin.readline

def solve():
    n, k = map(int, input().split())
    a = list(map(int, input().split()))

    INF = float('inf')
    # dp[j][cnt] = min d value, j is 0-indexed position (1-indexed position = j+1)
    # d[j] = (j+1) - a[j]

    dp = [[INF] * (k + 1) for _ in range(n)]

    for j in range(n):
        pos = j + 1  # 1-indexed
        d = pos - a[j]
        if d < 0 or d > pos - 1:
            continue
        dp[j][1] = d

    for cnt in range(2, k + 1):
        for j in range(n):
            pos_j = j + 1
            d_j = pos_j - a[j]
            if d_j < 0 or d_j > pos_j - 1:
                continue
            for i in range(j):
                pos_i = i + 1
                d_i = dp[i][cnt - 1]
                if d_i == INF:
                    continue
                if d_j >= d_i and d_j - d_i < pos_j - pos_i:
                    if d_j < dp[j][cnt]:
                        dp[j][cnt] = d_j

    ans = INF
    for j in range(n):
        if dp[j][k] < ans:
            ans = dp[j][k]

    print(-1 if ans == INF else ans)

t = int(input())
for _ in range(t):
    solve()
